#!/usr/bin/env python3
import base64, os, subprocess

b64_server = ""
os.makedirs(os.path.dirname("/var/www/konverta/server.js"), exist_ok=True)
open("/var/www/konverta/server.js", "wb").write(base64.b64decode(b64_server))
print("✓ /var/www/konverta/server.js")

print("\n✅ IPv4 fix aplicado!")
subprocess.run(["pm2", "restart", "konverta"])